import{_ as l}from"./nyalra_kb-7135827b.js";import{_ as p}from"./nyalra_no_mono-8344e451.js";import{_ as c,W as s,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as d,a0 as m,C as n}from"./framework-91490e6a.js";const f={},h=e("figure",null,[e("img",{src:l,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u=e("p",null,"第 51 回是 PR（恰饭回），恕我跳过。",-1),k={href:"https://tree-novel.com/works/episode/395b16936c1e6acf36c2193e3baeff2c.html",target:"_blank",rel:"noopener noreferrer"},b={href:"https://tree-novel.com/works/episode/2f7fd9b2386ff7951a0a3ccf93793795.html",target:"_blank",rel:"noopener noreferrer"},g=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),x=m('<hr><p>在过去的几个月里，我一直在认真地去健身房锻炼，所以总是感到肌肉酸痛。由于情况无法避免，我真的想去做个按摩！</p><p>……然而，不幸的是，由于我是夜行性的，要去按摩店确实有些困难。大多数按摩店在晚上九点左右关闭，而我通常在午夜之后才活跃起来。</p><p>尝试在网上搜索附近的按摩店，看看是否有一两家深夜营业的。啊，找到了。有一家泰式按摩店经营到深夜 3 点。太好了。那么马上就去吧！虽然这样想，但首先还是用店名搜索一下评价吧。正所谓投石问路。</p><p>结果，只找到了一篇店铺评价的文章。是大约 10 年前的个人博客。心生疑惑的同时，我打开了文章，果然如我所想！文章中关于按摩的内容只有两三行，其余全部都是关于从泰国店主那里得到的成人服务。他们之所以经营到深夜，是因为这方面的服务才是他们的主营业务。</p><p>并不是说我打算对这样的店铺敬而远之。我完全不在乎这种店在街上存在。但是，由于现在的我真的只是希望得到正规健康的按摩，所以如果被简单地导向这种服务，我就会感到困扰。比起下体的硬度，我更想让整个身体在真正的意义上变得有力。这和涩情漫画的情节方向完全相反呢。</p><p>在那篇博客中写道：「店主已经 50 多岁了，身材丰腴，所以说实话，我不打算再次光顾。」那么过了 10 年，店主现在应该已经 60 多岁了。嗯，即使有想去体验成人按摩的想法，我也并没有那么强烈的探究欲望，不会选择这样的特殊店铺。只是单纯地想要接受一次正规的按摩，决不会想让一个 60 多岁的泰国人碰触到微妙的地方。</p><p>稍微继续阅读发现，博主总结说：「虽然我不会再次光顾，但这也有它的独特魅力。店主是一个温柔开朗的人，而且确实有着泰式按摩店的独特风味，所以请不要误解。」真是出乎意料的支持。</p><p>确实，他的话是说得通的。从外国来的女性们在日本开设按摩店，通过一些独特的服务多赚一些钱。客户也会觉得有年轻日本女性的店价格会更高……这样的情况并不少见，而且由于对方是同国的年轻姐妹，所以能够想象到更轻松的沟通氛围。在这种情况下，能够满足想要舒爽下体的愿望，对于沉迷其中的人来说，简直是一箭双雕。这家店正是迎合了这样的需求。</p><p>......当然，虽然我现在并不寻求这方面的信息，但在这个社交网络时代，久违地看到个人博客发布信息，让我感到很高兴。这正是我在网络上追求的「信息碎片」本身。那些不知道是否有需求的专业知识和经验，孤零零地漂浮在互联网的海洋中，然后像这样被我偶然拾起，轻轻地印在我的脑海中。</p><p>「信息碎片」具有很强的随机性，而这种随机性发挥作用的可能性非常低。但是，偶尔由于某种奇迹，点与点之间连接起来，变成了非常有益的信息。我喜欢这个。这不是典型的「这个故事会对你有帮助！」或者「我整理了这些信息！」的感觉，而更像是悄悄地由个人放置，坚信这些信息肯定会传达给某人，就像扔出一瓶信件希望它能抵达一样。这就是我喜欢的感觉。PS 版『玲音』中我喜欢的地方就是这个！</p><p>虽然肌肉疼痛并没有完全治愈，但多亏这篇个人博客的评论，我久违地捡到了一些「信息碎片」，感觉温馨愉悦。实际上，如果没有这篇个人博客的评价，我可能会在泰式按摩店里，被 60 多岁的店主触摸到敏感部位。嗯，那作为一种经历也许是可以接受的。偶然间，这个神秘的信息确实帮助了某人。甚至发布者自己在数年后都无法想象以这种方式帮助了某人。这就是生活之所以有趣的原因，因为偶尔会有这种奇妙的事情发生。这让我再次感受到，生活是如此有趣，这是一个寒冷冬天的一幕。</p><hr><p><img src="'+p+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/8ebdc4a8b6cd50672f64375cd9dab3f7.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/84ac6d9687363b2f4641d06a00cd2b9e.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【SEGA 的 UFO 抓娃娃机型袋】只要在其中放入一些小玩偶之类的东西，不可思议地，家里的小物品就会变成 UFO 抓娃娃机的奖品。大小刚好能容纳黏土人，非常可爱。不知道在现代这种怀旧的设备还有多少存在。游戏中心深处也再听不到索尼克的 BGM 了。</p></blockquote>',15);function y(v,N){const a=n("ExternalLinkIcon"),r=n("RouterLink");return s(),_("div",null,[i(" more "),h,u,e("p",null,[t("第51回原文链接："),e("a",k,[t("第51回／秋葉原はユーサネイジアの夢を見るか？"),o(a)])]),e("p",null,[t("原文链接："),e("a",b,[t("第52回／情報のかけら"),o(a)])]),e("blockquote",null,[g,e("p",null,[o(r,{to:"/posts/Translate/nyalra_kb_50.html"},{default:d(()=>[t("【奈亚拉面壁自语】第50回｜社会责任的代价【231031】")]),_:1})])]),x])}const C=c(f,[["render",y],["__file","nyalra_kb_52.html.vue"]]);export{C as default};
